using System;
using System.IO;
using Aspose.Pdf;
using Aspose.Pdf.Annotations;

class Program
{
    static void Main(string[] args)
    {
        const string pdfPath = "input.pdf";
        if (!File.Exists(pdfPath))
        {
            Console.Error.WriteLine($"Error: PDF file not found at '{pdfPath}'.");
            return;
        }
        try
        {
            Document pdfDocument = new Document(pdfPath);
            IAppointment openAction = pdfDocument.OpenAction;
            if (openAction == null)
            {
                Console.WriteLine("The document does not have an OpenAction defined.");
                return;
            }
            if (openAction is GoToAction goToAction && goToAction.Destination != null)
            {
                if (goToAction.Destination is XYZExplicitDestination xyzDest)
                {
                    double zoom = xyzDest.Zoom;
                    Console.WriteLine($"Zoom factor from OpenAction: {zoom}");
                }
                else
                {
                    Console.WriteLine("OpenAction destination is not an XYZExplicitDestination; cannot extract zoom.");
                }
            }
            else
            {
                Console.WriteLine("OpenAction is not a GoToAction or does not contain a destination.");
            }
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"An error occurred while processing the PDF: {ex.Message}");
        }
    }
}

