/* Replace the LoadExcelToDataTable method with a CSV‑based implementation */
static DataTable LoadCsvToDataTable(string csvFilePath)
{
    var dt = new DataTable();
    using (var reader = new StreamReader(csvFilePath))
    {
        bool isFirstLine = true;
        while (!reader.EndOfStream)
        {
            var line = reader.ReadLine();
            if (string.IsNullOrWhiteSpace(line)) continue;
            var values = line.Split(',');
            if (isFirstLine)
            {
                foreach (var header in values) dt.Columns.Add(header.Trim());
                isFirstLine = false;
            }
            else
            {
                var row = dt.NewRow();
                for (int i = 0; i < values.Length && i < dt.Columns.Count; i++)
                    row[i] = values[i].Trim();
                dt.Rows.Add(row);
            }
        }
    }
    return dt;
}

