using System.Drawing.Imaging; // required for ImageFormat.Bmp
using Aspose.Pdf;
using Aspose.Pdf.Facades;
using Aspose.Pdf.Devices; // for Resolution

class Program
{
    static void Main(string[] args)
    {
        const string svgPath = "input.svg";
        const string outputFolder = "BmpOutput";
        try
        {
            if (!File.Exists(svgPath))
            {
                Console.Error.WriteLine($"Error: SVG file not found at '{svgPath}'.");
                return;
            }
            Directory.CreateDirectory(outputFolder);
            var loadOptions = new SvgLoadOptions();
            using (var pdfDocument = new Document(svgPath, loadOptions))
            using (var converter = new PdfConverter())
            {
                converter.BindPdf(pdfDocument);
                converter.StartPage = 1;
                converter.EndPage = pdfDocument.Pages.Count;
                converter.Resolution = new Resolution(150);
                int pageNumber = converter.StartPage;
                while (converter.HasNextImage())
                {
                    string bmpFile = Path.Combine(outputFolder, $"Page_{pageNumber}.bmp");
                    converter.GetNextImage(bmpFile, ImageFormat.Bmp);
                    Console.WriteLine($"Saved page {pageNumber} as BMP: {bmpFile}");
                    pageNumber++;
                }
            }
            Console.WriteLine("SVG → PDF → BMP conversion completed successfully.");
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"An error occurred: {ex.Message}");
        }
    }
}

