using System;
using System.IO;
using Aspose.Pdf;

class Program
{
    static void Main()
    {
        const string inputPath = "input.pdf";
        const string outputPath = "output.pdf";
        if (!File.Exists(inputPath))
        {
            Console.Error.WriteLine($"Error: Input file not found – {inputPath}");
            return;
        }
        try
        {
            Document pdfDocument = new Document(inputPath);
            for (int i = pdfDocument.EmbeddedFiles.Count; i >= 1; i--)
            {
                string attachmentName = pdfDocument.EmbeddedFiles[i].Name;
                pdfDocument.EmbeddedFiles.Delete(attachmentName);
            }
            pdfDocument.Save(outputPath);
            Console.WriteLine($"All attachments removed. Saved to '{outputPath}'.");
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"An error occurred: {ex.Message}");
        }
    }
}

