// Helper method to walk nested exceptions:
static bool ContainsDllNotFound(Exception ex)
{
    Exception? current = ex;
    while (current != null)
    {
        if (current is DllNotFoundException)
            return true;
        current = current.InnerException;
    }
    return false;
}

