    dst.Info.ModDate = src.Info.ModDate;
    dst.Info.Trapped = src.Info.Trapped;

    // Custom metadata entries
    dst.Info.ClearCustomData();
    foreach (var kvp in src.Info)
    {
        if (!DocumentInfo.IsPredefinedKey(kvp.Key))
        {
            dst.Info.Add(kvp.Key, kvp.Value);
        }
    }

    dst.Save(dstPath);
}

