guard-gdi-dependency-on-non-windows.code:
if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
{
    // GDI+ is guaranteed to be present on Windows
    doc.Save(outputPath);
    editor.MakeBooklet(inputPath, outputPath, leftPages, rightPages);
}
else
{
    try
    {
        doc.Save(outputPath);
    }
    catch (TypeInitializationException ex) when (ContainsDllNotFound(ex))
    {
        // handle missing libgdiplus, e.g., skip or log warning
    }

    try
    {
        editor.MakeBooklet(inputPath, outputPath, leftPages, rightPages);
    }
    catch (TypeInitializationException ex) when (ContainsDllNotFound(ex))
    {
        // handle missing libgdiplus
    }
}

// Helper used in the catch clause
private static bool ContainsDllNotFound(Exception? ex)
{
    while (ex != null)
    {
        if (ex is DllNotFoundException) return true;
        ex = ex.InnerException;
    }
    return false;
}

