handle-gdiplus-missing-on-non-windows.code:
using System.Runtime.InteropServices;

void SaveDocument(Document doc, string path)
{
    if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
    {
        doc.Save(path);
        return;
    }
    try
    {
        doc.Save(path);
    }
    catch (TypeInitializationException ex) when (ContainsDllNotFound(ex))
    {
        // Handle missing libgdiplus gracefully
    }
}

bool ContainsDllNotFound(Exception? ex)
{
    while (ex != null)
    {
        if (ex is DllNotFoundException) return true;
        ex = ex.InnerException;
    }
    return false;
}

