XNamespace newNs = "http://custom.org/xfdf";
XDocument original = XDocument.Load(stream);
XDocument custom = new XDocument(
    new XElement(
        newNs + original.Root.Name.LocalName,
        original.Root.Attributes().Where(a => !a.IsNamespaceDeclaration),
        original.Root.Elements().Select(e => ChangeNamespace(e, newNs))
    )
);

static XElement ChangeNamespace(XElement element, XNamespace ns) =>
    new XElement(
        ns + element.Name.LocalName,
        element.Attributes().Where(a => !a.IsNamespaceDeclaration),
        element.Elements().Select(e => ChangeNamespace(e, ns))
    );

