use-pdfextractor-hasnextpage-text-image-.code:
using (PdfExtractor extractor = new PdfExtractor())
{
    if (!File.Exists(pdfPath)) return false; // optional guard
    extractor.BindPdf(pdfPath);

    extractor.ExtractText();
    bool hasText = false;
    while (extractor.HasNextPageText())
    {
        extractor.GetText(new MemoryStream()); // advance page
        hasText = true;
        break;
    }

    extractor.ExtractImage();
    bool hasImage = false;
    while (extractor.HasNextImage())
    {
        extractor.GetNextImage(new MemoryStream()); // advance image
        hasImage = true;
        break;
    }

    return hasText && hasImage;
}

