retry-autofiller-file-access.code:
int attempt = 0;
const int maxRetries = 3;
while (attempt < maxRetries)
{
    try
    {
        var autoFiller = new AutoFiller();
        autoFiller.BindPdf(templatePath); // may throw FileNotFoundException
        autoFiller.ImportDataTable(dataTable);
        autoFiller.Save(outputPath);
        break; // success
    }
    catch (FileNotFoundException fnf)
    {
        // retry – the file might be created by another process
        attempt++;
        Thread.Sleep(delayMs);
    }
    catch (IOException io)
    {
        // retry transient I/O errors (e.g., sharing violations)
        attempt++;
        Thread.Sleep(delayMs);
    }
}

